SELECT COUNT(*) AS QUANTIDADE FROM CARGO CG JOIN SERVIDOR S ON S.PK_SIAPE = CG.FK_SIAPE WHERE S.GENERO = 'FEMININO' AND (LOWER(S.AREA_INGRESSO) LIKE LOWER('%engenharia eletrica%') OR LOWER(S.AREA_INGRESSO) LIKE LOWER('%engenharia eletrica%') OR LOWER(S.AREA_INGRESSO_OG) LIKE LOWER('%engenharia eletrica%') OR LOWER(S.AREA_INGRESSO_OG) LIKE LOWER('%engenharia eletrica%')) AND CG.SIGLA_CAMPUS = 'ITU' AND ((LOWER(CG.FUNCAO) LIKE LOWER('%coordenador%') OR LOWER(CG.ATIVIDADE) LIKE LOWER('%coordenador%')) AND (LOWER(CG.FUNCAO) LIKE LOWER('%curso%') OR LOWER(CG.SETOR) LIKE LOWER('%curso%')) AND (LOWER(CG.FUNCAO) LIKE LOWER('%substit%') OR LOWER(CG.ATIVIDADE) LIKE LOWER('%substit%'))) AND CG.DATA_ENTRADA <= DATE('now') AND COALESCE(CG.DATA_SAIDA, DATE('now')) >= CAST(DATE('now', '-5 years') AS DATE)